// ── Fallback API Functions ──

export function getCountryConfig(iso3: string) {
  return COUNTRY_CONFIGS[iso3.toUpperCase()] ?? COUNTRY_CONFIGS.NGA;
}

export function getRecalibratedData(_country: string, isco08?: string) {
  if (isco08) {
    const occ = NGA_RECALIBRATED.occupations.find(o => o.isco08 === isco08);
    if (occ) return { occupations: [occ] };
  }
  return NGA_RECALIBRATED;
}

export function getPolicymakerAggregates(_country: string) {
  return NGA_POLICYMAKER_AGGREGATES;
}

export function getAdjacencyData(isco08: string) {
  return (ADJACENCY_GRAPH as Record<string, any>)[isco08] ?? null;
}

export function getTaskComposition(isco08: string) {
  return (TASK_COMPOSITION as Record<string, any>)[isco08] ?? null;
}

export function getCrosswalkData(isco08: string) {
  const tc = getTaskComposition(isco08);
  const adj = getAdjacencyData(isco08);
  if (!tc) return null;
  return {
    isco08,
    title: tc.isco_title ?? isco08,
    automation_probability: 0.5,
    linked_soc_codes: [],
    esco_skills: [],
    onet_tasks: tc.top_tasks?.slice(0, 5) ?? [],
    task_composition: tc.task_composition ?? {},
  };
}

/** Build a QueryResponse-shaped object from static data */
export function getQueryResponse(isco08: string, country: string) {
  const recal = getRecalibratedData(country, isco08);
  const occ = recal.occupations?.[0];
  const adj = getAdjacencyData(isco08);
  return {
    occupation: { isco08, title: occ?.title ?? isco08 },
    demand_signals: { total_jobs: 0, avg_salary_ngn: 0 },
    adjacency_pathways: (adj?.adjacencies ?? []).slice(0, 5).map((a: any) => ({
      target_isco08: a.target_isco,
      target_title: a.target_title,
      skill_overlap_pct: Math.round((a.skill_overlap_jaccard ?? 0) * 100),
      missing_skills_count: a.missing_skills?.length ?? 0,
      wage_uplift_pct: 0,
      gap_description: `${a.shared_skills?.length ?? 0} shared skills identified`,
    })),
    ai_risk: {
      original: occ?.original_frey_osborne ?? 0.5,
      recalibrated: occ?.recalibrated_probability ?? 0.5,
      tier: occ?.risk_tier ?? "medium",
    },
    econometric_signals: {
      labour_force_participation_pct: 60,
      labour_force_participation_trend: "stable" as const,
      youth_unemployment_pct: 14,
    },
    data_limitations: ["Static fallback data — live API unavailable"],
  };
}
